>     }
>   }
>
>   private selectNearest(candidates: Entity[]): Entity {
>     return candidates.reduce((nearest, current) =>
>       current.getPosition().distance(this.owner.getPosition()) <
>       nearest.getPosition().distance(this.owner.getPosition())
>         ? current : nearest
>     );
>   }
>
>   private selectWeakest(candidates: Entity[]): Entity {
