387	### 3. 目标选择系统
388	
389	战斗中如何从多个候选目标中选择攻击对象？目标选择系统回答这个问题。
390	
391	#### 常见选择策略
392	
393	| 策略 | 描述 | 适用场景 |
394	|------|------|---------|
395	| **最近优先** | 选择距攻击者最近的目标 | 防御塔、近战单位 |
396	| **最弱优先** | 选择生命值最低的目标 | 输出型角色、集火策略 |
397	| **最强优先** | 选择生命值最高的目标 | 坦克仇恨拉住 |
398	| **随机选择** | 随机选择目标 | 辅助敌人、AI 随机性 |
399	| **权重系统** | 根据多因素加权计算优先级 | 复杂 AI 决策 |
400	
401	#### 优先级权重系统
402	
403	实际游戏中，通常需要综合考虑多个因素：
404	
405	```typescript
406	// TargetSelection.ts
407	interface TargetingParams {
408	  distanceWeight: number;    // 距离权重
409	  healthWeight: number;      // 生命值权重（低血量高优先级）
410	  threatWeight: number;      // 仇恨值权重
411	}
412	
413	selectTarget(
414	  candidates: Entity[],
415	  params: TargetingParams
416	): Entity | null {
417	  if (candidates.length === 0) return null;
418	
419	  let bestTarget: Entity | null = null;
420	  let highestScore = -Infinity;
421	
422	  for (const candidate of candidates) {
423	    const score = this.calculateScore(candidate, params);
424	    if (score > highestScore) {
425	      highestScore = score;
426	      bestTarget = candidate;
427	    }
428	  }
429	
430	  return bestTarget;
431	}
432	
433	private calculateScore(
434	  target: Entity,
435	  params: TargetingParams
436	): number {
437	  const distScore = 1 / (1 + this.owner.getPosition().distance(target.getPosition()));
438	  const healthScore = 1 - (target.getHealth() / target.getMaxHealth()); // 血量越低分数越高
439	  const threatScore = target.getThreatLevel();
440	
441	  return (
442	    distScore * params.distanceWeight +
443	    healthScore * params.healthWeight +
444	    threatScore * params.threatWeight
445	  );
446	}
447	```
448	
449	> [!example]- 目标选择实现
450	> ```typescript
451	> // 不同策略的实现
452	> enum TargetStrategy {
453	>   NEAREST,
454	>   WEAKEST,
455	>   STRONGEST,
456	>   RANDOM,
457	>   WEIGHTED,
458	> }
459	>
460	> class TargetSelector {
461	>   select(
462	>     candidates: Entity[],
463	>     strategy: TargetStrategy,
464	>     params?: TargetingParams
465	>   ): Entity | null {
466	>     if (candidates.length === 0) return null;
467	>
468	>     switch (strategy) {
469	>       case TargetStrategy.NEAREST:
470	>         return this.selectNearest(candidates);
471	>       case TargetStrategy.WEAKEST:
472	>         return this.selectWeakest(candidates);
473	>       case TargetStrategy.STRONGEST:
474	>         return this.selectStrongest(candidates);
475	>       case TargetStrategy.RANDOM:
476	>         return candidates[Math.floor(Math.random() * candidates.length)];
477	>       case TargetStrategy.WEIGHTED:
478	>         return this.selectWeighted(candidates, params!);
479	>     }
480	>   }
481	>
482	>   private selectNearest(candidates: Entity[]): Entity {
483	>     return candidates.reduce((nearest, current) =>
484	>       current.getPosition().distance(this.owner.getPosition()) <
485	>       nearest.getPosition().distance(this.owner.getPosition())
486	>         ? current : nearest
487	>     );
488	>   }
489	>
490	>   private selectWeakest(candidates: Entity[]): Entity {
491	>     return candidates.reduce((weakest, current) =>
492	>       current.getHealth() < weakest.getHealth() ? current : weakest
493	>     );
494	>   }
495	> }
496	> ```
