### 7. 云存档同步

云存档让玩家可以在多个设备上继续游戏，但也带来了新的挑战：冲突解决。

#### 同步冲突解决策略

```
场景：玩家在设备 A 玩了 1 小时，积累了 1000 金币
      玩家在设备 B 也玩了 1 小时，积累了 800 金币
      现在要同步，哪个是正确的？
```

**策略一：最后写入胜出（Last Write Wins）**

```
简单直接，以时间戳为准
优点：实现简单
缺点：可能丢失一方的进度
```

**策略二：合并策略**

```
各设备的数据合并
- 货币：取最大值
- 已解锁内容：取并集
- 统计：取最大值
```

**策略三：服务器权威**

```
关键操作必须在服务器验证
客户端只负责上传操作日志
服务器重放操作，生成最终状态
```

> [!example]- 点击查看冲突解决实现
> ```typescript
> /**
>  * 云存档同步管理器
>  */
> class CloudSyncManager {
>   private localSave: GlobalSave;
>   private cloudSave: GlobalSave | null;
>
>   /**
>    * 解决存档冲突
>    * 使用"最后写入胜出 + 数据合并"策略
>    */
>   resolveConflict(local: GlobalSave, cloud: GlobalSave): GlobalSave {
>     // 基础策略：谁新用谁
>     const localNewer = local.lastSaveTime > cloud.lastSaveTime;
>     const base = localNewer ? local : cloud;
>
>     // 合并差异
>     return {
>       ...base,
>       // 货币取最大值（防止丢失）
>       coins: Math.max(local.coins, cloud.coins),
>       gems: Math.max(local.gems, cloud.gems),
>
>       // 已解锁内容取并集
>       unlockedTowers: [...new Set([...local.unlockedTowers, ...cloud.unlockedTowers])],
>       unlockedSkills: [...new Set([...local.unlockedSkills, ...cloud.unlockedSkills])],
>
>       // 成就取并集
>       achievements: [...new Set([...local.achievements, ...cloud.achievements])],
>
>       // 统计数据取最大值
>       statistics: {
>         totalRuns: Math.max(local.statistics.totalRuns, cloud.statistics.totalRuns),
>         highestFloor: Math.max(local.statistics.highestFloor, cloud.statistics.highestFloor),
>         // ...
>       },
>
>       // 保留各方的设置（无法合并，使用较新版本的）
>       settings: localNewer ? local.settings : cloud.settings,
>
>       // 更新时间戳
>       lastSaveTime: Date.now(),
>     };
>   }
>
>   /**
>    * 离线期间的数据合并
>    * 适用于"离线收益"等功能
>    */
>   mergeOfflineProgress(local: GlobalSave, offlineRewards: OfflineRewards): GlobalSave {
>     return {
>       ...local,
>       coins: local.coins + offlineRewards.coins,
>       gems: local.gems + offlineRewards.gems,
>       statistics: {
>         ...local.statistics,
>         // 离线期间的资源产出
>       }
>     };
>   }
> }
> ```

#### 离线到上线合并

```typescript
/**
 * 处理离线期间的数据
 */
async function handleOfflineMerge(
>  local: GlobalSave,
>  cloud: GlobalSave
): Promise<GlobalSave> {
  const syncManager = new CloudSyncManager();
  const conflictResolver = new ConflictResolver();

  // 如果本地和云端都有数据，需要解决冲突
  if (cloud.lastSaveTime > local.lastSaveTime) {
    // 云端更新，需要检查是否有关键操作
    const conflict = conflictResolver.detectConflict(local, cloud);

    if (conflict.hasConflict) {
      // 存在冲突，使用合并策略
      return syncManager.resolveConflict(local, cloud);
    }

    // 无冲突，使用云端数据覆盖本地
    return cloud;
  }

  // 本地更新，需要上传到云端
  await cloudStorage.save('current_save', local);
  return local;
}
```

### 8. 完整存档管理器实现

整合以上所有组件，完整实现一个 SaveManager。

> [!example]- 点击查看完整 SaveManager 实现
> ```typescript
> /**
>  * 存档管理器 - 整合所有功能
>  * 功能：
>  * - 自动/手动保存
>  * - 数据加密
>  * - 版本迁移
>  * - 云同步
>  * - 防作弊检测
>  */
> class SaveManager {
>   private storage: SaveStorage;
>   private encryption: EncryptionService;
>   private migration: SaveMigrationManager;
>   private antiCheat: AntiCheatSystem;
>   private syncManager: CloudSyncManager;
>
>   private currentSave: GlobalSave | null = null;
>   private autoSaveInterval: number | null = null;
>   private isDirty: boolean = false; // 是否有未保存的更改
>
>   constructor(storage: SaveStorage) {
>     this.storage = storage;
>     this.encryption = new AESEncryption();
>     this.migration = new SaveMigrationManager();
>     this.antiCheat = new AntiCheatSystem();
>     this.syncManager = new CloudSyncManager();
>   }
>
>   /**
>    * 初始化存档管理器
>    */
>   async initialize(): Promise<void> {
>     // 尝试加载存档
>     const rawData = await this.storage.load('global_save');

>     if (rawData) {
>       // 解密
>       const decrypted = this.encryption.decrypt(rawData);
>       const parsed = JSON.parse(decrypted) as GlobalSave;

>       // 版本迁移
>       this.currentSave = this.migration.migrateToLatest(parsed);

>       // 验证数据完整性
>       const validation = this.antiCheat.validateDataRanges(this.currentSave);
>       if (!validation.valid) {
>         console.warn('Save data validation failed:', validation.errors);
>         // 决定是回滚还是警告用户
>       }
>     } else {
>       // 创建新存档
>       this.currentSave = this.createNewSave();
>     }

>     // 启动自动保存
>     this.startAutoSave();
>   }

>   /**
>    * 创建新存档
>    */
>   createNewSave(): GlobalSave {
>     return {
>       version: 4, // 当前最新版本
>       playerId: this.generatePlayerId(),
>       coins: 0,
>       gems: 0,
>       unlockedTowers: ['tower_basic'],
>       towerLevels: { tower_basic: 1 },
>       unlockedSkills: [],
>       achievements: [],
>       statistics: {
>         totalRuns: 0,
>         totalDamage: 0,
>         totalKills: 0,
>         highestFloor: 1,
>         highestScore: 0,
>       },
>       settings: {
>         musicVolume: 0.7,
>         sfxVolume: 0.8,
>         graphicsQuality: 'medium',
>         language: 'zh-CN',
>       },
>       prestigeLevel: 0,
>       prestigeCurrency: 0,
>       lastSaveTime: Date.now(),
>       totalPlayTime: 0,
>     };
>   }

>   /**
>    * 获取当前存档
>    */
>   getSave(): GlobalSave {
>     if (!this.currentSave) {
>       throw new Error('Save not initialized');
>     }
>     return { ...this.currentSave }; // 返回副本，防止意外修改
>   }

>   /**
>    * 更新存档（标记为脏，等待自动或手动保存）
>    */
>   updateSave(updater: (save: GlobalSave) => void): void {
>     if (!this.currentSave) return;

>     updater(this.currentSave);
>     this.currentSave.lastSaveTime = Date.now();
>     this.isDirty = true;

>     // 可选：关键操作立即保存
>     // await this.save();
>   }

>   /**
>    * 保存存档
>    */
>   async save(): Promise<void> {
>     if (!this.currentSave || !this.isDirty) return;

>     const data = JSON.stringify(this.currentSave);
>     const encrypted = this.encryption.encrypt(data);

>     await this.storage.save('global_save', encrypted);
>     this.isDirty = false;

>     console.log(`Save completed at ${new Date().toISOString()}`);
>   }

>   /**
>    * 启动自动保存
>    */
>   private startAutoSave(intervalMs = 30000): void {
>     if (this.autoSaveInterval) {
>       clearInterval(this.autoSaveInterval);
>     }

>     this.autoSaveInterval = window.setInterval(async () => {
>       if (this.isDirty) {
>         await this.save();
>       }
>     }, intervalMs);
>   }

>   /**
>    * 同步到云端
>    */
>   async syncToCloud(): Promise<void> {
>     if (!this.currentSave) return;

>     await this.save(); // 先保存本地

>     try {
>       await this.syncManager.upload(this.currentSave);
>     } catch (error) {
