>       // 后续可以加入重试逻辑
>     }
>   }

>   /**
>    * 从云端同步
>    */
>   async syncFromCloud(): Promise<void> {
>     const cloudSave = await this.syncManager.download();

>     if (!cloudSave) return;

>     if (!this.currentSave) {
>       this.currentSave = cloudSave;
>       return;
>     }

>     // 解决冲突并合并
>     this.currentSave = this.syncManager.resolveConflict(this.currentSave, cloudSave);
>     await this.save();
>   }

>   /**
>    * 导出存档（用于迁移或备份）
>    */
>   async exportSave(): Promise<string> {
>     if (!this.currentSave) {
>       throw new Error('No save to export');
>     }
>     // 导出时也加密，保护数据
>     return this.encryption.encrypt(JSON.stringify(this.currentSave));
>   }

>   /**
>    * 导入存档
>    */
>   async importSave(exportedData: string): Promise<void> {
>     const decrypted = this.encryption.decrypt(exportedData);
