> [!abstract]- GameManager.ts — 游戏主管理器
```typescript
import { _decorator, Component, Node } from 'cc';
import { EventManager } from './EventManager';
import { SaveManager } from './SaveManager';
import { AudioManager } from './AudioManager';
import { TowerManager } from '../Tower/TowerManager';
import { EnemyManager } from '../Enemy/EnemyManager';
import { MapGenerator } from '../Map/MapGenerator';
import { BlessingSystem } from '../Roguelike/BlessingSystem';

const { ccclass, property } = _decorator;

@ccclass('GameManager')
export class GameManager extends Component {
    // 单例
    private static _instance: GameManager;
    public static get instance(): GameManager {
        return GameManager._instance;
    }

    // 子系统
    public eventManager: EventManager = new EventManager();
    public saveManager: SaveManager = new SaveManager();
    public audioManager: AudioManager = new AudioManager();
    public towerManager: TowerManager = null;
    public enemyManager: EnemyManager = null;
    public mapGenerator: MapGenerator = null;
    public blessingSystem: BlessingSystem = null;

    // 游戏状态
    private _gameState: 'menu' | 'playing' | 'paused' | 'gameover' = 'menu';
    public get gameState(): string {
        return this._gameState;
    }

    // 当前地牢层数
    private _floor: number = 1;
    public get floor(): number {
        return this._floor;
    }

    onLoad() {
        if (GameManager._instance) {
            this.destroy();
            return;
        }
        GameManager._instance = this;

        // 初始化子系统
        this.towerManager = this.addComponent(TowerManager);
        this.enemyManager = this.addComponent(EnemyManager);
        this.mapGenerator = this.addComponent(MapGenerator);
        this.blessingSystem = this.addComponent(BlessingSystem);

        // 加载存档
        this.saveManager.load();

        // 监听事件
        this.eventManager.on('enemy_killed', this.onEnemyKilled, this);
        this.eventManager.on('tower_built', this.onTowerBuilt, this);
        this.eventManager.on('floor_complete', this.onFloorComplete, this);
    }

    start() {
        // 显示开始界面
        this.setState('menu');
    }

    /** 开始新游戏或继续 */
    public startGame() {
        this._floor = this.saveManager.data.currentFloor || 1;
        this.mapGenerator.generate();
        this.setState('playing');
    }

    /** 设置游戏状态 */
    public setState(state: typeof this._gameState) {
        this._gameState = state;
        this.eventManager.emit('game_state_changed', state);
    }

    /** 敌人被击杀 */
    private onEnemyKilled(enemy: any) {
        const gold = enemy.goldValue || 10;
        this.saveManager.addGold(gold);
        this.audioManager.playSFX('enemy_dead');
    }

    /** 建塔 */
    private onTowerBuilt(tower: any) {
        this.audioManager.playSFX('tower_build');
    }

    /** 楼层完成 */
    private onFloorComplete() {
        this._floor++;
        this.saveManager.data.currentFloor = this._floor;

        // 检查是否触发遗物选择
        if (this._floor % 3 === 0) {
            this.blessingSystem.showSelection();
        } else {
            // 直接进入下一层
            this.scheduleOnce(() => {
                this.mapGenerator.generate();
            }, 2);
        }
    }

    /** 游戏结束 */
    public gameOver() {
        this.setState('gameover');
        this.saveManager.save();
    }

    onDestroy() {
        this.eventManager.off('enemy_killed', this.onEnemyKilled, this);
        this.eventManager.off('tower_built', this.onTowerBuilt, this);
        this.eventManager.off('floor_complete', this.onFloorComplete, this);

        if (GameManager._instance === this) {
            GameManager._instance = null;
        }
    }
}
```

> [!abstract]- EventManager.ts — 事件管理器
```typescript
type EventCallback = (arg?: any) => void;

export class EventManager {
    private listeners: Map<string, EventCallback[]> = new Map();

    /** 监听事件 */
    on(event: string, callback: EventCallback, target?: any) {
        if (!this.listeners.has(event)) {
            this.listeners.set(event, []);
        }

        const wrappedCallback = target
            ? callback.bind(target)
            : callback;

        this.listeners.get(event).push(wrappedCallback);
    }

    /** 触发事件 */
    emit(event: string, arg?: any) {
        const callbacks = this.listeners.get(event) || [];
        callbacks.forEach(cb => cb(arg));
    }

    /** 取消监听 */
    off(event: string, callback: EventCallback, target?: any) {
        const callbacks = this.listeners.get(event) || [];
        const index = callbacks.findIndex(cb => cb === callback);
        if (index !== -1) {
            callbacks.splice(index, 1);
        }
    }

    /** 清空所有监听 */
    clear() {
        this.listeners.clear();
    }
}
```

> [!abstract]- SaveManager.ts — 存档管理器
```typescript
import { SaveManager } from './SaveManager';

// 存档数据结构
interface SaveData {
    currentFloor: number;
    gold: number;
    towers: string[];          // 已解锁的塔 ID
    blessings: string[];       // 已获得的遗物 ID
    permanentUpgrades: {       // 永久升级
        damageBonus: number;
        goldBonus: number;
        offlineEfficiency: number;
    };
    lastSaveTime: number;      // 上次离线时间（用于计算离线收益）
}

const SAVE_KEY = 'roguelike_td_save';

@ccclass('SaveManager')
export class SaveManager extends Component {
    public data: SaveData = this.getDefaultData();

    private getDefaultData(): SaveData {
        return {
            currentFloor: 1,
            gold: 0,
            towers: ['arrow', 'cannon'],  // 默认解锁两种塔
            blessings: [],
            permanentUpgrades: {
                damageBonus: 0,
                goldBonus: 0,
                offlineEfficiency: 1.0,
            },
            lastSaveTime: Date.now(),
        };
    }

    /** 加载存档 */
    public load(): void {
        const str = localStorage.getItem(SAVE_KEY);
        if (str) {
            try {
                const loaded = JSON.parse(str);
                this.data = { ...this.getDefaultData(), ...loaded };
            } catch (e) {
                console.warn('存档加载失败，使用默认存档');
                this.data = this.getDefaultData();
            }
        }
    }

    /** 保存存档 */
    public save(): void {
        this.data.lastSaveTime = Date.now();
        localStorage.setItem(SAVE_KEY, JSON.stringify(this.data));
    }

    /** 添加金币 */
    public addGold(amount: number): void {
        const bonus = 1 + this.data.permanentUpgrades.goldBonus;
        this.data.gold += Math.floor(amount * bonus);
    }

    /** 消耗金币 */
    public spendGold(amount: number): boolean {
        if (this.data.gold >= amount) {
            this.data.gold -= amount;
            return true;
        }
        return false;
    }

    /** 计算离线收益 */
    public calculateOfflineEarnings(): number {
        const now = Date.now();
        const elapsed = (now - this.data.lastSaveTime) / 1000; // 秒
        const maxOfflineSeconds = 8 * 60 * 60; // 最多 8 小时
        const effectiveSeconds = Math.min(elapsed, maxOfflineSeconds);

        // 每 10 秒产出 1 金币（简化计算）
        const baseEarnings = effectiveSeconds / 10;
        const efficiency = this.data.permanentUpgrades.offlineEfficiency;

        return Math.floor(baseEarnings * efficiency);
    }

    /** 重置（转生） */
    public prestige(): void {
        // 保存永久升级进度
        const prestigePoints = Math.floor(this.data.currentFloor / 10);

        // 重置存档但保留永久升级
        this.data = this.getDefaultData();
        this.data.permanentUpgrades.offlineEfficiency += prestigePoints * 0.1;

        this.save();
    }
}
```

