### 3. 第二步：地图与移动（Day 4-7）

地图系统是塔防游戏的基础。一个好的地图系统需要：
1. 随机生成地牢布局
2. 正确渲染瓦片地图
3. 玩家移动控制
4. 相机跟随

#### 3.1 地牢生成器

> [!abstract]- MapGenerator.ts — 程序化地牢生成
```typescript
import { _decorator, Component, Node } from 'cc';
import { TileRenderer } from './TileRenderer';

const { ccclass, property } = _decorator;

// 地图配置
interface MapConfig {
    width: number;    // 格子宽度
    height: number;   // 格子高度
    roomMinSize: number;
    roomMaxSize: number;
    corridorWidth: number;
}

interface Room {
    x: number;
    y: number;
    width: number;
    height: number;
    centerX: number;
    centerY: number;
}

@ccclass('MapGenerator')
export class MapGenerator extends Component {
    @property(TileRenderer)
    tileRenderer: TileRenderer = null;

    // 地图数据（0 = 空地，1 = 墙，2 = 敌人出生点，3 = 玩家出生点）
    private mapData: number[][] = [];

    private config: MapConfig = {
        width: 20,
        height: 15,
        roomMinSize: 4,
        roomMaxSize: 8,
        corridorWidth: 2,
    };

    /** 生成新地图 */
    public generate(): void {
        // 1. 初始化空地图
        this.initMap();

        // 2. 生成房间
        const rooms = this.generateRooms();

        // 3. 连接房间（走廊）
        this.connectRooms(rooms);

        // 4. 放置出生点
        this.placeSpawnPoints(rooms);

        // 5. 渲染地图
        this.tileRenderer.render(this.mapData);
    }

    /** 初始化空地图（全为墙） */
    private initMap(): void {
        this.mapData = [];
        for (let y = 0; y < this.config.height; y++) {
            this.mapData[y] = [];
            for (let x = 0; x < this.config.width; x++) {
                this.mapData[y][x] = 1; // 1 = 墙
            }
        }
    }

    /** 生成随机房间 */
    private generateRooms(): Room[] {
        const rooms: Room[] = [];
        const attempts = 20;

        for (let i = 0; i < attempts; i++) {
            const w = this.randomInt(this.config.roomMinSize, this.config.roomMaxSize);
            const h = this.randomInt(this.config.roomMinSize, this.config.roomMaxSize);
            const x = this.randomInt(1, this.config.width - w - 1);
            const y = this.randomInt(1, this.config.height - h - 1);

            const newRoom: Room = {
                x, y, width: w, height: h,
                centerX: Math.floor(x + w / 2),
                centerY: Math.floor(y + h / 2),
            };

            // 检查是否与现有房间重叠
            let overlaps = false;
            for (const room of rooms) {
                if (this.roomsOverlap(newRoom, room)) {
                    overlaps = true;
                    break;
                }
            }

            if (!overlaps) {
                rooms.push(newRoom);
                this.carveRoom(newRoom);
            }
        }

        return rooms;
    }

    /** 在地图上开凿房间 */
    private carveRoom(room: Room): void {
        for (let y = room.y; y < room.y + room.height; y++) {
            for (let x = room.x; x < room.x + room.width; x++) {
                if (this.inBounds(x, y)) {
                    this.mapData[y][x] = 0;
                }
            }
        }
    }

    /** 连接两个房间 */
    private connectRooms(rooms: Room[]): void {
        for (let i = 1; i < rooms.length; i++) {
            const prev = rooms[i - 1];
            const curr = rooms[i];

            // 随机选择水平优先或垂直优先
            if (Math.random() < 0.5) {
                this.carveHorizontalCorridor(prev.centerX, curr.centerX, prev.centerY);
                this.carveVerticalCorridor(prev.centerY, curr.centerY, curr.centerX);
            } else {
                this.carveVerticalCorridor(prev.centerY, curr.centerY, prev.centerX);
                this.carveHorizontalCorridor(prev.centerX, curr.centerX, curr.centerY);
            }
        }
    }

    private carveHorizontalCorridor(x1: number, x2: number, y: number): void {
        const minX = Math.min(x1, x2);
        const maxX = Math.max(x1, x2);
        for (let x = minX; x <= maxX; x++) {
            if (this.inBounds(x, y)) {
                this.mapData[y][x] = 0;
            }
        }
    }

    private carveVerticalCorridor(y1: number, y2: number, x: number): void {
        const minY = Math.min(y1, y2);
        const maxY = Math.max(y1, y2);
        for (let y = minY; y <= maxY; y++) {
            if (this.inBounds(x, y)) {
                this.mapData[y][x] = 0;
            }
        }
    }

    /** 放置出生点 */
    private placeSpawnPoints(rooms: Room[]): void {
        if (rooms.length < 2) return;

        // 第一个房间放玩家出生点
        const startRoom = rooms[0];
        this.mapData[startRoom.centerY][startRoom.centerX] = 3;

        // 最后一个房间放敌人出生点
        const endRoom = rooms[rooms.length - 1];
        this.mapData[endRoom.centerY][endRoom.centerX] = 2;
    }

    /** 检查房间是否重叠 */
    private roomsOverlap(a: Room, b: Room, padding: number = 1): boolean {
        return !(
            a.x + a.width + padding < b.x ||
            b.x + b.width + padding < a.x ||
            a.y + a.height + padding < b.y ||
            b.y + b.height + padding < a.y
        );
    }

    private randomInt(min: number, max: number): number {
        return Math.floor(Math.random() * (max - min + 1)) + min;
    }

    private inBounds(x: number, y: number): boolean {
        return x >= 0 && x < this.config.width && y >= 0 && y < this.config.height;
    }

    /** 判断某格子是否可通行 */
    public isWalkable(x: number, y: number): boolean {
        if (!this.inBounds(x, y)) return false;
        return this.mapData[y][x] === 0;
    }

    /** 获取敌人出生点 */
    public getEnemySpawnPoint(): { x: number, y: number } {
        for (let y = 0; y < this.config.height; y++) {
            for (let x = 0; x < this.config.width; x++) {
                if (this.mapData[y][x] === 2) {
                    return { x, y };
                }
            }
        }
        return { x: this.config.width - 2, y: this.config.height - 2 };
    }
}
