import { _decorator, Component, Node, Vec3, input, Input, EventKeyboard } from 'cc';
import { InputManager } from '../Core/InputManager';

const { ccclass, property } = _decorator;

@ccclass('PlayerController')
export class PlayerController extends Component {
    @property
    moveSpeed: number = 200;  // 像素/秒

    @property
    gridSize: number = 32;   // 每格 32 像素

    private targetPos: Vec3 = null;
    private isMoving: boolean = false;

    start() {
        input.on(Input.EventType.KEY_DOWN, this.onKeyDown, this);
    }

    /** 键盘输入 */
    private onKeyDown(event: EventKeyboard) {
        const keyCode = event.keyCode;
        let dx = 0, dy = 0;

        switch (keyCode) {
            case Input.KeyCode.ARROW_UP:
            case Input.KeyCode.KEY_W:
                dy = 1;
                break;
            case Input.KeyCode.ARROW_DOWN:
            case Input.KeyCode.KEY_S:
                dy = -1;
                break;
            case Input.KeyCode.ARROW_LEFT:
            case Input.KeyCode.KEY_A:
                dx = -1;
                break;
            case Input.KeyCode.ARROW_RIGHT:
            case Input.KeyCode.KEY_D:
                dx = 1;
                break;
            default:
                return;
        }

        this.tryMove(dx, dy);
    }

    /** 尝试向某方向移动 */
    public tryMove(dx: number, dy: number): boolean {
        const mapGenerator = GameManager.instance.mapGenerator;

        // 当前格子
        const currentX = Math.floor(this.node.position.x / this.gridSize);
        const currentY = Math.floor(this.node.position.y / this.gridSize);

        // 目标格子
        const targetX = currentX + dx;
        const targetY = currentY + dy;

        // 检查是否可以移动
        if (!mapGenerator.isWalkable(targetX, targetY)) {
            return false;
        }

        // 设置目标位置
        this.targetPos = new Vec3(
            targetX * this.gridSize,
            targetY * this.gridSize,
            0
        );
        this.isMoving = true;

        return true;
    }

    update(dt: number) {
        if (!this.isMoving || !this.targetPos) return;

        // 移动到目标位置
        const currentPos = this.node.position;
        const direction = this.targetPos.subtract(currentPos);
        const distance = direction.length();

        if (distance < 1) {
            // 到达目标
            this.node.setPosition(this.targetPos);
            this.isMoving = false;
            this.targetPos = null;
        } else {
            // 移动
            direction.normalize();
            const moveStep = this.moveSpeed * dt;
            const nextPos = currentPos.add(direction.multiplyScalar(moveStep));

            // 检查是否会穿过障碍物（简化处理）
            this.node.setPosition(nextPos);
        }
    }

    onDestroy() {
        input.off(Input.EventType.KEY_DOWN, this.onKeyDown, this);
    }
}
