            fireRate: 1.0,
        });

        this.towerTypes.set('cannon', {
            id: 'cannon',
            name: '炮塔',
            prefab: null,
            cost: 100,
            range: 120,
            damage: 25,
            fireRate: 0.5,
        });

        this.towerTypes.set('frost', {
            id: 'frost',
            name: '冰塔',
            prefab: null,
            cost: 80,
            range: 100,
            damage: 5,
            fireRate: 2.0,
        });
    }

    /** 尝试放置塔 */
    public tryPlaceTower(gridX: number, gridY: number, towerId: string): boolean {
        // 检查位置是否有效
        if (!this.canPlaceTower(gridX, gridY)) {
            return false;
        }

        // 检查金币是否足够
        const towerType = this.towerTypes.get(towerId);
        if (!towerType) return false;

        if (!GameManager.instance.saveManager.spendGold(towerType.cost)) {
            return false; // 金币不足
        }

        // 创建塔
        const tower = this.createTower(towerType, gridX, gridY);
        this.placedTowers.push(tower);

        // 触发事件
        GameManager.instance.eventManager.emit('tower_built', tower);

        return true;
    }

    /** 检查某位置是否可以放塔 */
    private canPlaceTower(gridX: number, gridY: number): boolean {
        const mapGenerator = GameManager.instance.mapGenerator;

        // 必须在地牢内且是空地
        if (!mapGenerator.isWalkable(gridX, gridY)) {
            return false;
        }

        // 不能已经有塔
        for (const tower of this.placedTowers) {
            const tx = Math.floor(tower.node.position.x / this.gridSize);
            const ty = Math.floor(tower.node.position.y / this.gridSize);
            if (tx === gridX && ty === gridY) {
                return false;
            }
        }

        return true;
    }

    /** 创建塔实例 */
    private createTower(type: TowerType, gridX: number, gridY: number): TowerBase {
        // 实际项目从 Prefab 实例化
        const node = new Node(type.name);
        node.setPosition(gridX * this.gridSize, gridY * this.gridSize, 0);
        this.node.addChild(node);

        const tower = node.addComponent(TowerBase);
        tower.init(type);

        return tower;
    }

    /** 获取范围内最近的敌人 */
    public getNearestEnemy(x: number, y: number, range: number): any {
        let nearest: any = null;
        let nearestDist = Infinity;

        const enemies = GameManager.instance.enemyManager.getActiveEnemies();

        for (const enemy of enemies) {
            const dx = enemy.node.position.x - x;
            const dy = enemy.node.position.y - y;
            const dist = Math.sqrt(dx * dx + dy * dy);

            if (dist <= range && dist < nearestDist) {
                nearest = enemy;
                nearestDist = dist;
            }
        }

        return nearest;
    }

    /** 所有塔升级（遗物效果） */
    public upgradeAllTowers(damageBonus: number) {
        for (const tower of this.placedTowers) {
            tower.addDamageBonus(damageBonus);
        }
    }
}
