#### 4.2 A* 寻路实现

> [!abstract]- AStarPathfinder.ts — A* 寻路算法
```typescript
interface PathNode {
    x: number;
    y: number;
    g: number;  // 从起点到当前节点的实际代价
    h: number;  // 从当前节点到终点的估算代价（启发函数）
    f: number;  // g + h，总代价
    parent: PathNode | null;
}

export class AStarPathfinder {
    private gridSize: number = 32;
    private width: number = 20;
    private height: number = 15;
    private mapData: number[][] = [];

    /** 设置网格数据 */
    public setMapData(mapData: number[][]) {
        this.mapData = mapData;
        this.height = mapData.length;
        this.width = mapData[0]?.length || 0;
    }

    /** 寻路 */
    public findPath(
        startX: number, startY: number,
        endX: number, endY: number
    ): { x: number, y: number }[] {
        // 边界检查
        if (!this.isValidPos(startX, startY) || !this.isValidPos(endX, endY)) {
            return [];
        }

        // 如果终点不可通行，尝试找最近的可通行点
        if (!this.isWalkable(endX, endY)) {
            const nearest = this.findNearestWalkable(endX, endY);
            if (!nearest) return [];
            endX = nearest.x;
            endY = nearest.y;
        }

        const openList: PathNode[] = [];
        const closedSet = new Set<string>();

        const startNode: PathNode = {
            x: startX, y: startY,
            g: 0,
            h: this.heuristic(startX, startY, endX, endY),
            f: 0,
            parent: null,
        };
        startNode.f = startNode.g + startNode.h;

        openList.push(startNode);

        while (openList.length > 0) {
            // 找到 f 值最小的节点
            openList.sort((a, b) => a.f - b.f);
            const current = openList.shift();

            // 到达终点
            if (current.x === endX && current.y === endY) {
                return this.reconstructPath(current);
            }

            closedSet.add(`${current.x},${current.y}`);

            // 遍历邻居（4 方向）
            const neighbors = [
                { x: current.x + 1, y: current.y },
                { x: current.x - 1, y: current.y },
                { x: current.x, y: current.y + 1 },
                { x: current.x, y: current.y - 1 },
            ];

            for (const neighbor of neighbors) {
                const { x, y } = neighbor;

                // 检查是否有效
                if (!this.isValidPos(x, y) || !this.isWalkable(x, y)) {
                    continue;
                }

                // 已在关闭列表
                if (closedSet.has(`${x},${y}`)) {
                    continue;
                }

                const g = current.g + 1;  // 每步代价为 1
                const h = this.heuristic(x, y, endX, endY);
                const f = g + h;

                // 检查是否在开放列表
                const existingIdx = openList.findIndex(n => n.x === x && n.y === y);
                if (existingIdx !== -1) {
                    if (g < openList[existingIdx].g) {
                        openList[existingIdx].g = g;
                        openList[existingIdx].f = f;
                        openList[existingIdx].parent = current;
                    }
                } else {
                    openList.push({
                        x, y, g, h, f,
                        parent: current,
                    });
                }
            }
        }

        // 找不到路径
        return [];
    }

    /** 启发函数（曼哈顿距离） */
    private heuristic(x1: number, y1: number, x2: number, y2: number): number {
        return Math.abs(x1 - x2) + Math.abs(y1 - y2);
    }

    /** 重构路径 */
    private reconstructPath(node: PathNode): { x: number, y: number }[] {
        const path: { x: number, y: number }[] = [];
        let current: PathNode | null = node;

        while (current) {
            path.unshift({ x: current.x, y: current.y });
            current = current.parent;
        }

        return path;
    }

    /** 检查坐标是否有效 */
    private isValidPos(x: number, y: number): boolean {
        return x >= 0 && x < this.width && y >= 0 && y < this.height;
    }

    /** 检查是否可通行（0 = 空地） */
    private isWalkable(x: number, y: number): boolean {
        if (!this.isValidPos(x, y)) return false;
        return this.mapData[y][x] === 0;
    }

    /** 找最近的可通行点 */
    private findNearestWalkable(x: number, y: number): { x: number, y: number } | null {
        for (let r = 1; r < 10; r++) {
            for (let dx = -r; dx <= r; dx++) {
                for (let dy = -r; dy <= r; dy++) {
                    if (Math.abs(dx) + Math.abs(dy) !== r) continue;
                    const nx = x + dx;
                    const ny = y + dy;
                    if (this.isWalkable(nx, ny)) {
                        return { x: nx, y: ny };
                    }
                }
            }
        }
        return null;
    }
}
