    // 活动中的敌人
    private activeEnemies: EnemyBase[] = [];

    // 波次配置
    private waveConfigs: WaveConfig[] = [];
    private currentWave: number = 0;
    private enemiesSpawned: number = 0;
    private spawnTimer: number = 0;

    private isWaveActive: boolean = false;

    start() {
        this.initWaveConfigs();
    }

    /** 初始化波次配置 */
    private initWaveConfigs() {
        // 根据楼层动态生成（简化处理）
        // 实际项目可以配置表驱动
    }

    /** 开始新一波 */
    public startWave(waveNumber: number) {
        this.currentWave = waveNumber;
        this.isWaveActive = true;
        this.enemiesSpawned = 0;
        this.spawnTimer = 0;

        // 设置寻路数据
        const mapData = GameManager.instance.mapGenerator.mapData;
        this.pathfinder.setMapData(mapData);
    }

    /** 生成波次敌人 */
    private updateWave(dt: number) {
        if (!this.isWaveActive) return;

        this.spawnTimer -= dt;
        if (this.spawnTimer > 0) return;

        const totalEnemies = 5 + this.currentWave * 2;
        if (this.enemiesSpawned >= totalEnemies) {
            // 本波完成
            if (this.activeEnemies.length === 0) {
                this.isWaveActive = false;
                GameManager.instance.eventManager.emit('wave_complete', this.currentWave);
            }
            return;
        }

        // 生成敌人
        this.spawnEnemy();
        this.enemiesSpawned++;
        this.spawnTimer = 1.0;  // 每秒生成一个
    }

    /** 生成单个敌人 */
    private spawnEnemy() {
        const spawnPoint = GameManager.instance.mapGenerator.getEnemySpawnPoint();

        const enemyNode = new Node('Enemy');
        enemyNode.setPosition(
            spawnPoint.x * this.gridSize,
            spawnPoint.y * this.gridSize,
            0
        );
        this.node.addChild(enemyNode);

        const enemy = enemyNode.addComponent(EnemyBase);

        // 计算敌人属性（根据波次缩放）
        const hp = 50 + this.currentWave * 20;
        const damage = 5 + this.currentWave * 2;
        const speed = 30 + Math.random() * 20;

        enemy.init({
            hp,
            maxHp: hp,
            damage,
            speed,
            pathfinder: this.pathfinder,
        });

        this.activeEnemies.push(enemy);
    }

    /** 获取活动敌人列表 */
    public getActiveEnemies(): EnemyBase[] {
        return this.activeEnemies;
    }

    /** 移除敌人 */
    public removeEnemy(enemy: EnemyBase) {
        const idx = this.activeEnemies.indexOf(enemy);
        if (idx !== -1) {
            this.activeEnemies.splice(idx, 1);
        }
    }

    update(dt: number) {
        // 更新波次生成
        this.updateWave(dt);
    }
}
