import { AStarPathfinder } from '../Map/AStarPathfinder';

const { ccclass, property } = _decorator;

@ccclass('EnemyBase')
export class EnemyBase extends Component {
    public maxHp: number = 100;
    public hp: number = 100;
    public damage: number = 10;
    public speed: number = 50;  // 像素/秒
    public goldValue: number = 10;

    private path: { x: number, y: number }[] = [];
    private pathIndex: number = 0;
    private pathfinder: AStarPathfinder = null;

    private isDead: boolean = false;

    @property
    gridSize: number = 32;

    /** 初始化敌人 */
    public init(config: any) {
        this.maxHp = config.hp;
        this.hp = config.hp;
        this.damage = config.damage;
        this.speed = config.speed;
        this.pathfinder = config.pathfinder;

        // 计算初始路径
        this.calculatePath();
    }

    /** 计算到玩家的路径 */
    private calculatePath() {
        const startX = Math.floor(this.node.position.x / this.gridSize);
        const startY = Math.floor(this.node.position.y / this.gridSize);

        // 玩家位置（简化：假设玩家在出生点）
        // 实际需要从 GameManager 获取
        const playerSpawn = GameManager.instance.mapGenerator.getEnemySpawnPoint();
        const endX = playerSpawn.x;
        const endY = playerSpawn.y;

        // A* 寻路
        this.path = this.pathfinder.findPath(startX, startY, endX, endY);
        this.pathIndex = 0;
    }

    /** 受到伤害 */
    public takeDamage(amount: number) {
        this.hp -= amount;

        // 受伤反馈
        this.playHitEffect();

        if (this.hp <= 0 && !this.isDead) {
            this.die();
        }
    }

    /** 死亡 */
    private die() {
        this.isDead = true;

        // 触发死亡事件
        GameManager.instance.eventManager.emit('enemy_killed', this);

        // 播放死亡效果
        this.playDeathEffect();

        // 从管理器移除
        GameManager.instance.enemyManager.removeEnemy(this);

        // 销毁
        this.scheduleOnce(() => {
            this.node.destroy();
        }, 0.5);
    }

    /** 播放受伤效果 */
    private playHitEffect() {
        // 闪白效果
        // ... (省略)
    }

    /** 播放死亡效果 */
    private playDeathEffect() {
        // 爆炸/消失动画
        // ... (省略)
    }

    update(dt: number) {
        if (this.isDead || this.path.length === 0) return;

        // 移动向路径点
        const target = this.path[this.pathIndex];
        if (!target) return;

        const targetPos = new Vec3(
            target.x * this.gridSize,
            target.y * this.gridSize,
            0
        );

        const currentPos = this.node.position;
        const direction = targetPos.subtract(currentPos);
        const distance = direction.length();

        if (distance < 5) {
            // 到达路径点
            this.pathIndex++;
            if (this.pathIndex >= this.path.length) {
                // 到达终点（玩家位置），造成伤害
                this.attackPlayer();
            }
        } else {
            // 移动
            direction.normalize();
            const moveStep = this.speed * dt;
            const nextPos = currentPos.add(direction.multiplyScalar(moveStep));
            this.node.setPosition(nextPos);
        }
    }

    /** 攻击玩家 */
    private attackPlayer() {
        // 玩家扣血
        // ... (省略)
        this.die();  // 敌人到终点后消失
    }
}
